"use strict";(globalThis.webpackChunkdoqumentation=globalThis.webpackChunkdoqumentation||[]).push([[7841],{9368(i,e,t){t.r(e),t.d(e,{assets:()=>l,contentTitle:()=>n,default:()=>d,frontMatter:()=>r,metadata:()=>a,toc:()=>u});const a=JSON.parse('{"id":"guides/intro-to-patterns","title":"Flusso di sviluppo","description":"Un Qiskit pattern \xe8 l\'insieme dei passi generali da seguire per eseguire un problema specifico di dominio su hardware quantistico.","source":"@site/i18n/it/docusaurus-plugin-content-docs/current/guides/intro-to-patterns.mdx","sourceDirName":"guides","slug":"/guides/intro-to-patterns","permalink":"/guides/intro-to-patterns","draft":false,"unlisted":false,"editUrl":"https://github.com/JanLahmann/doQumentation/tree/main/docs/guides/intro-to-patterns.mdx","tags":[],"version":"current","frontMatter":{"title":"Flusso di sviluppo","description":"Un Qiskit pattern \xe8 l\'insieme dei passi generali da seguire per eseguire un problema specifico di dominio su hardware quantistico."},"sidebar":"tutorialsSidebar","previous":{"title":"Estendere Qiskit in Python con C","permalink":"/guides/c-extension-for-python"},"next":{"title":"Ultimi aggiornamenti","permalink":"/guides/latest-updates"}}');var o=t(74848),s=t(28453);const r={title:"Flusso di sviluppo",description:"Un Qiskit pattern \xe8 l'insieme dei passi generali da seguire per eseguire un problema specifico di dominio su hardware quantistico."},n="Flusso di sviluppo {#development-workflow}",l={},u=[{value:"Mappare il problema su circuit quantistici e operatori",id:"map-the-problem-to-quantum-circuits-and-operators",level:2},{value:"Ottimizzare per l&#39;hardware di destinazione",id:"optimize-for-target-hardware",level:2},{value:"Eseguire sull&#39;hardware di destinazione",id:"execute-on-target-hardware",level:2},{value:"Post-elaborare i risultati",id:"post-process-results",level:2}];function c(i){const e={em:"em",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",strong:"strong",ul:"ul",...(0,s.R)(),...i.components};return(0,o.jsxs)(o.Fragment,{children:["\n",(0,o.jsx)(e.header,{children:(0,o.jsx)(e.h1,{id:"development-workflow",children:"Flusso di sviluppo"})}),"\n",(0,o.jsxs)(e.p,{children:["Il termine ",(0,o.jsx)(e.em,{children:"Qiskit pattern"})," descrive il flusso di sviluppo per scomporre problemi specifici di dominio e contestualizzare le capacit\xe0 necessarie in fasi distinte. Questo approccio consente la composizione fluida di nuove funzionalit\xe0 sviluppate dai ricercatori di IBM Quantum\xae (e da altri) e apre la strada a un futuro in cui i compiti di calcolo quantistico vengono eseguiti da una potente infrastruttura di calcolo eterogenea (CPU/GPU/QPU). Blocchi o gruppi di blocchi eseguono i passi di un pattern, con il Qiskit SDK che fornisce un importante strato fondazionale, supportato da altri strumenti o servizi sviluppati da IBM Quantum o dalla comunit\xe0 open-source quantistica. I Qiskit pattern permettono agli esperti di dominio di specificare un problema e comporre gli strumenti (blocchi) che realizzano un Qiskit pattern. Tale pattern pu\xf2 poi essere eseguito localmente, tramite servizi cloud, o distribuito con Qiskit Serverless."]}),"\n",(0,o.jsx)(e.p,{children:"I quattro passi di un Qiskit pattern sono i seguenti:"}),"\n",(0,o.jsxs)(e.ul,{children:["\n",(0,o.jsxs)(e.li,{children:[(0,o.jsx)(e.strong,{children:"Map"})," \u2014 mappatura del problema su circuit quantistici e operatori"]}),"\n",(0,o.jsxs)(e.li,{children:[(0,o.jsx)(e.strong,{children:"Optimize"})," \u2014 ottimizzazione per l'hardware di destinazione"]}),"\n",(0,o.jsxs)(e.li,{children:[(0,o.jsx)(e.strong,{children:"Execute"})," \u2014 esecuzione sull'hardware di destinazione"]}),"\n",(0,o.jsxs)(e.li,{children:[(0,o.jsx)(e.strong,{children:"Post-process"})," \u2014 post-elaborazione dei risultati"]}),"\n"]}),"\n",(0,o.jsx)(e.p,{children:"Ogni passo \xe8 descritto in dettaglio nelle sezioni seguenti."}),"\n",(0,o.jsx)(e.h2,{id:"map-the-problem-to-quantum-circuits-and-operators",children:"Mappare il problema su circuit quantistici e operatori"}),"\n",(0,o.jsx)(e.p,{children:"Questo passo descrive come si parte da un problema classico e si determina come mapparlo su un computer quantistico. Ad esempio, in applicazioni come la chimica e la simulazione quantistica, questo passo prevede generalmente la costruzione di un circuito quantistico che rappresenta l'Hamiltoniano che si sta cercando di risolvere. Durante questa fase, per certi problemi, potrebbe essere utile specificare fin dall'inizio la mappatura del problema sui qubit nel reticolo heavy-hex (o gross) dell'hardware IBM\xae, qualora la struttura del problema si presti a un'ottimizzazione anticipata. Vale anche la pena considerare gi\xe0 in questa fase quale sar\xe0 il risultato del particolare algoritmo, in preparazione al successivo passo di esecuzione \u2014 ad esempio, se il risultato desiderato prevede l'inferenza di funzioni di correlazione tramite test di Hadamard, potresti prepararti a utilizzare il Sampler, mentre specificare osservabili richiederebbe l'Estimator e potrebbe offrire numerose opzioni di mitigazione degli errori."}),"\n",(0,o.jsx)(e.p,{children:"L'output di questo passo \xe8 normalmente una raccolta di circuit o operatori quantistici che possono essere ottimizzati per l'hardware nel passo successivo."}),"\n",(0,o.jsx)(e.h2,{id:"optimize-for-target-hardware",children:"Ottimizzare per l'hardware di destinazione"}),"\n",(0,o.jsx)(e.p,{children:"In questo passo si prendono i circuit astratti (o operatori) prodotti nella fase di mappatura e si esegue su di essi una serie di ottimizzazioni. Queste possono includere la mappatura del percorso e del layout del circuito sull'hardware fisico dei qubit, la conversione nei gate base dell'hardware e la riduzione del numero di operazioni \u2014 tutto finalizzato a massimizzare la probabilit\xe0 di successo nel successivo passo di esecuzione. A questo punto potresti anche voler testare i tuoi circuit con un simulatore prima di eseguirli su hardware reale nel passo successivo."}),"\n",(0,o.jsx)(e.p,{children:"Durante questa fase, i circuit astratti devono essere transpilati in circuit ISA (Instruction Set Architecture). Un circuito ISA \xe8 composto esclusivamente da gate compresi dall'hardware di destinazione (gate base) e da eventuali gate multi-qubit necessari per rispettare i vincoli di connettivit\xe0 (coupling map). Solo i circuit ISA possono essere eseguiti sull'hardware IBM tramite IBM Qiskit Runtime."}),"\n",(0,o.jsx)(e.h2,{id:"execute-on-target-hardware",children:"Eseguire sull'hardware di destinazione"}),"\n",(0,o.jsx)(e.p,{children:"Questo passo prevede l'esecuzione dei tuoi circuit sull'hardware e produce gli output del calcolo quantistico. I circuit ISA prodotti nel passo precedente possono essere eseguiti utilizzando la primitiva Sampler o Estimator di Qiskit Runtime, inizializzata localmente sul tuo computer oppure da un cluster o altro ambiente di calcolo eterogeneo. Possono essere eseguiti in un Batch, che consente la transpilazione parallela per una maggiore efficienza di calcolo classico, oppure in una Session, che permette l'implementazione efficiente di compiti iterativi senza ritardi di accodamento. Durante questo passo \xe8 anche possibile configurare alcune tecniche di soppressione e mitigazione degli errori fornite da Qiskit Runtime."}),"\n",(0,o.jsx)(e.p,{children:"A seconda che si utilizzi la primitiva Sampler o Estimator, il risultato di questo passo sar\xe0 diverso. Con il Sampler, l'output sar\xe0 costituito da misurazioni per-shot sotto forma di bitstring. Con l'Estimator, l'output sar\xe0 costituito dai valori di aspettativa degli osservabili corrispondenti a grandezze fisiche o funzioni di costo."}),"\n",(0,o.jsx)(e.h2,{id:"post-process-results",children:"Post-elaborare i risultati"}),"\n",(0,o.jsx)(e.p,{children:"Questo passo finale consiste nel ricombinare gli output del passo precedente per ottenere il risultato desiderato. Pu\xf2 includere una serie di operazioni di elaborazione dati classica, come la visualizzazione dei risultati, tecniche di mitigazione degli errori di readout, la marginalizzazione di distribuzioni di quasi-probabilit\xe0 per ricavare risultati su sottoinsiemi pi\xf9 piccoli di qubit, oppure la post-selezione su propriet\xe0 intrinseche del problema, come spin totale, parit\xe0 o conservazione delle particelle mediante l'eliminazione di osservabili non fisici."}),"\n",(0,o.jsx)(e.p,{children:"Man mano che il settore evolve dalla costruzione di circuit su misura a flussi di lavoro su scala utility, la flessibilit\xe0 e la semplicit\xe0 con cui i Qiskit pattern consentono agli utenti di comporre i diversi passi del pattern aprono il calcolo quantistico a un'ampia variet\xe0 di applicazioni e tecniche, rendendole facilmente accessibili agli scienziati del calcolo quantistico."})]})}function d(i={}){const{wrapper:e}={...(0,s.R)(),...i.components};return e?(0,o.jsx)(e,{...i,children:(0,o.jsx)(c,{...i})}):c(i)}},28453(i,e,t){t.d(e,{R:()=>r,x:()=>n});var a=t(96540);const o={},s=a.createContext(o);function r(i){const e=a.useContext(s);return a.useMemo(function(){return"function"==typeof i?i(e):{...e,...i}},[e,i])}function n(i){let e;return e=i.disableParentContext?"function"==typeof i.components?i.components(o):i.components||o:r(i.components),a.createElement(s.Provider,{value:e},i.children)}}}]);